#!/usr/bin/env node
'use strict';
/**
 * A3 gate bundler + stamper (tooling — the live publish it feeds is PO-GATED).
 *
 * n8n Cloud Code nodes can't `require`, so the single-source-of-truth lib/gates
 * modules have to be VENDORED INLINE into the node text. This bundler assembles
 * all lib/gates/*.js into ONE namespaced block:
 *
 *   /* ==== QTP-GATES:BEGIN sha=<16hex> ==== *\/
 *   const QTPGates = (function () { <module bodies> return { <exports> }; })();
 *   /* ==== QTP-GATES:END ==== *\/
 *
 * The node then calls QTPGates.finalMtfPass(...) etc. — no copy of the logic
 * lives in the node, so it cannot drift. The IIFE isolates gate scope from the
 * node's own variables (no collisions with a 500-line node).
 *
 * This file is PURE TOOLING: buildBundle() + stamp()/extract() for tests and for
 * a future CI stamp step. It does NOT publish to n8n. Making vaqfCaELhOEWnkdo
 * actually call QTPGates is a live SM change — PO auth + E2E required (A3.5+).
 *
 * CLI:
 *   node .ci/bundle-gates.js            # print the bundle + its sha
 *   node .ci/bundle-gates.js --sha      # print just the sha
 */
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const ROOT = path.resolve(__dirname, '..');
const GATES_DIR = path.join(ROOT, 'lib', 'gates');

const BEGIN = (sha) => `/* ==== QTP-GATES:BEGIN sha=${sha} (generated by .ci/bundle-gates.js — DO NOT EDIT BY HAND) ==== */`;
const END = `/* ==== QTP-GATES:END ==== */`;
const BEGIN_RE = /\/\* ==== QTP-GATES:BEGIN[^*]*==== \*\//;
const END_RE = /\/\* ==== QTP-GATES:END ==== \*\//;

function sha16(s) { return crypto.createHash('sha256').update(s).digest('hex').slice(0, 16); }

// Pull the exported identifier names out of a `module.exports = { a, b, c };` tail.
function parseExportNames(src, file) {
  const m = src.match(/module\.exports\s*=\s*\{([\s\S]*?)\};/);
  if (!m) throw new Error(`${file}: no module.exports = { ... } found`);
  return m[1]
    .split(',')
    .map((s) => s.replace(/\/\/.*$/gm, '').trim())
    .filter(Boolean)
    .map((s) => s.split(':')[0].trim())   // support "name: value" though gates use shorthand
    .filter(Boolean);
}

// Strip the parts that don't belong inside the shared IIFE body.
function moduleBody(src) {
  return src
    .replace(/^\s*'use strict';\s*$/m, '')                 // drop per-module directive
    .replace(/^\s*const .*=\s*require\([^)]*\);\s*$/gm, '') // drop any require (gates have none)
    .replace(/module\.exports\s*=\s*\{[\s\S]*?\};\s*/g, '') // drop the export tail
    .trim();
}

function buildBundle() {
  const files = fs.readdirSync(GATES_DIR).filter((f) => f.endsWith('.js')).sort();
  if (files.length === 0) throw new Error('lib/gates has no modules to bundle');

  const bodies = [];
  const exportNames = [];
  const seen = new Map(); // name -> file, to catch cross-module collisions

  for (const f of files) {
    const src = fs.readFileSync(path.join(GATES_DIR, f), 'utf8');
    for (const n of parseExportNames(src, f)) {
      if (seen.has(n)) throw new Error(`export name collision: "${n}" in both ${seen.get(n)} and ${f} — namespace or rename before bundling`);
      seen.set(n, f);
      exportNames.push(n);
    }
    bodies.push(`  // ---- lib/gates/${f} ----\n` + moduleBody(src).split('\n').map((l) => (l ? '  ' + l : l)).join('\n'));
  }

  const inner =
    `const QTPGates = (function () {\n` +
    `  'use strict';\n\n` +
    bodies.join('\n\n') +
    `\n\n  return { ${exportNames.join(', ')} };\n` +
    `})();`;

  const sha = sha16(inner);
  const block = `${BEGIN(sha)}\n${inner}\n${END}`;
  return { code: block, inner, sha, names: exportNames, files };
}

// Replace an existing QTP-GATES block in node text, or insert after the first
// 'use strict'; (or at the top). Idempotent: stamping twice yields identical text.
function stamp(nodeText, block) {
  if (BEGIN_RE.test(nodeText) && END_RE.test(nodeText)) {
    const start = nodeText.search(BEGIN_RE);
    const endMatch = nodeText.match(END_RE);
    const end = nodeText.indexOf(endMatch[0]) + endMatch[0].length;
    return nodeText.slice(0, start) + block + nodeText.slice(end);
  }
  const us = nodeText.match(/^\s*'use strict';\s*$/m);
  if (us) {
    const at = nodeText.indexOf(us[0]) + us[0].length;
    return nodeText.slice(0, at) + '\n\n' + block + '\n' + nodeText.slice(at);
  }
  return block + '\n\n' + nodeText;
}

// Extract the bundle block (between and including sentinels) from stamped node text.
function extract(nodeText) {
  if (!BEGIN_RE.test(nodeText) || !END_RE.test(nodeText)) return null;
  const start = nodeText.search(BEGIN_RE);
  const endMatch = nodeText.match(END_RE);
  const end = nodeText.indexOf(endMatch[0]) + endMatch[0].length;
  return nodeText.slice(start, end);
}

// sha recorded inside a BEGIN sentinel (for drift-diff of a stamped node).
function shaOfStamped(nodeText) {
  const m = nodeText.match(/QTP-GATES:BEGIN sha=([0-9a-f]{16})/);
  return m ? m[1] : null;
}

module.exports = { buildBundle, stamp, extract, shaOfStamped, sha16, BEGIN_RE, END_RE };

if (require.main === module) {
  const b = buildBundle();
  if (process.argv.includes('--sha')) { console.log(b.sha); }
  else {
    console.error(`[bundle-gates] ${b.files.length} modules, ${b.names.length} exports, sha=${b.sha}`);
    console.log(b.code);
  }
}
